# -------------------------# DeepSeek API 调用函数（用于润色）- 改进版本# -------------------------import requestsimport logging# 配置日志记录logging.basicConfig(    level=logging.INFO,    format='%(asctime)s - %(levelname)s - %(message)s',    filename='deepseek_api.log',    filemode='a')def call_deepseek_api(text_to_rewrite):    """    调用DeepSeek API进行文本润色    :param text_to_rewrite: 需要润色的文本    :return: 润色后的文本，如果API调用失败则返回原始文本    """    # 修复API_URL中的反引号问题    API_URL = "https://api.deepseek.com/v1/chat/completions"    API_KEY = "sk-cea68c36b6e74d928f3289fe4fe0180a"  # 替换为你的API KEY    headers = {        "Content-Type": "application/json",        "Authorization": f"Bearer {API_KEY}"    }    payload = {        "model": "deepseek-chat",        "messages": [            {"role": "system", "content": "你是一个文本润色助手。请将以下内容用正式风格润色，保持原意不变，并控制在500字以内。"},            {"role": "user", "content": text_to_rewrite}        ],        "max_tokens": 500,        "temperature": 0.7    }    try:        logging.info(f"开始调用DeepSeek API，待润色文本: {text_to_rewrite[:50]}...")        response = requests.post(API_URL, headers=headers, json=payload, timeout=10)        logging.info(f"API调用响应状态码: {response.status_code}")               if response.status_code == 200:            result = response.json()            rewritten_text = result['choices'][0]['message']['content']            logging.info(f"API调用成功，润色后的文本: {rewritten_text[:50]}...")            return rewritten_text.strip()        else:            logging.error(f"API调用失败，状态码: {response.status_code}")            logging.error(f"错误信息: {response.text}")            return text_to_rewrite    except requests.Timeout:        logging.error("API调用超时")        return text_to_rewrite    except requests.ConnectionError:        logging.error("网络连接错误")        return text_to_rewrite    except KeyError as e:        logging.error(f"API响应格式错误，缺少字段: {e}")        return text_to_rewrite    except Exception as e:        logging.error(f"网络请求异常: {e}")        return text_to_rewrite# 测试函数if __name__ == "__main__":    test_text = "这是一个测试文本，用于测试DeepSeek API的文本润色功能。"    print(f"原始文本: {test_text}")    rewritten = call_deepseek_api(test_text)    print(f"润色后: {rewritten}")    print("测试完成！请查看deepseek_api.log文件获取详细日志。")